import heapq
class Solution:
    def minOperations(self, queries):
        total = 0
        for l, r in queries:
            counts = []
            for x in range(l, r + 1):
                c, v = 0, x
                while v > 0:
                    v //= 4
                    c += 1
                counts.append(c)
            heap = [-c for c in counts if c > 0]
            heapq.heapify(heap)
            ops = 0
            while len(heap) >= 2:
                a = -heapq.heappop(heap)
                b = -heapq.heappop(heap)
                ops += 1
                a -= 1
                b -= 1
                if a > 0:
                    heapq.heappush(heap, -a)
                if b > 0:
                    heapq.heappush(heap, -b)
            if len(heap) == 1:
                ops += -heap[0]
            total += ops
        return total

