class Solution:
    def minOperations(self, queries):
        total = 0
        for l, r in queries:
            sum_c, max_c = 0, 0
            k, lo = 1, 1
            while lo <= r:
                hi = lo * 4 - 1
                a = max(l, lo)
                b = min(r, hi)
                if a <= b:
                    cnt = b - a + 1
                    sum_c += k * cnt
                    if k > max_c:
                        max_c = k
                lo *= 4
                k += 1
            total += max(max_c, (sum_c + 1) // 2)
        return total

