var minOperations = function(queries) {
    let total = 0;
    for (const [l, r] of queries) {
        let sumC = 0, maxC = 0, k = 1, lo = 1;
        while (lo <= r) {
            const hi = lo * 4 - 1;
            const a = Math.max(l, lo);
            const b = Math.min(r, hi);
            if (a <= b) {
                const cnt = b - a + 1;
                sumC += k * cnt;
                if (k > maxC) maxC = k;
            }
            lo *= 4;
            k += 1;
        }
        total += Math.max(maxC, Math.ceil(sumC / 2));
    }
    return total;
};
